<?php

namespace Ivoz\Provider\Infrastructure\Persistence\Doctrine;

use Doctrine\Persistence\ManagerRegistry;
use Ivoz\Core\Domain\Service\EntityPersisterInterface;
use Ivoz\Core\Infrastructure\Persistence\Doctrine\Repository\DoctrineRepository;
use Ivoz\Provider\Domain\Model\Webhook\Webhook;
use Ivoz\Provider\Domain\Model\Webhook\WebhookRepository;
use Ivoz\Provider\Domain\Model\Webhook\WebhookInterface;
use Ivoz\Provider\Domain\Model\Webhook\WebhookDto;

/**
 * WebhookDoctrineRepository
 *
 * This class was generated by ivoz:make:repositories command.
 * Add your own custom repository methods below.
 *
 * @extends DoctrineRepository<WebhookInterface, WebhookDto>
 */
class WebhookDoctrineRepository extends DoctrineRepository implements WebhookRepository
{
    public function __construct(
        ManagerRegistry $registry,
        EntityPersisterInterface $entityPersisterInterface,
    ) {
        parent::__construct(
            $registry,
            Webhook::class,
            $entityPersisterInterface
        );
    }

    /**
     * @return WebhookInterface[]
     */
    public function findMatchingWebhooks(int $brandId, ?int $companyId, ?int $ddiId): array
    {
        $qb = $this->createQueryBuilder('w')
            ->where('w.brand = :brandId')
            ->setParameter('brandId', $brandId);

        if ($companyId !== null) {
            $qb->andWhere('w.company IS NULL OR w.company = :companyId')
                ->setParameter('companyId', $companyId);
        } else {
            $qb->andWhere('w.company IS NULL');
        }

        if ($ddiId !== null) {
            $qb->andWhere('w.ddi IS NULL OR w.ddi = :ddiId')
                ->setParameter('ddiId', $ddiId);
        } else {
            $qb->andWhere('w.ddi IS NULL');
        }

        return $qb->getQuery()->getResult();
    }
}
